#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

#define MAX_PROCESSES 100

typedef struct {
 int pid;
 int arrival_time;
 int burst_time;
 int priority;
 int remaining_time;
 int completion_time;
 int turnaround_time;
 int waiting_time;
 int start_time;
} Process;

// Global variables
Process processes[MAX_PROCESSES];
int n = 0;

// Initialize process
void init_process(int pid, int at, int bt) {
 processes[n].pid = pid;
 processes[n].arrival_time = at;
 processes[n].burst_time = bt;
 processes[n].remaining_time = bt;
 processes[n].priority = 0;
 processes[n].completion_time = 0;
 processes[n].turnaround_time = 0;
 processes[n].waiting_time = 0;
 processes[n].start_time = -1;
 n++;
}

// Reset process fields for reuse
void reset_processes() {
 for (int i = 0; i < n; i++) {
 processes[i].remaining_time = processes[i].burst_time;
 processes[i].completion_time = 0;
 processes[i].turnaround_time = 0;
 processes[i].waiting_time = 0;
 processes[i].start_time = -1;
 }
}

// Print results
void print_results(char* algorithm_name) {
 printf("\n============================================================\n");
 printf("%s\n", algorithm_name);
 printf("============================================================\n\n");

 printf("Process Details:\n");
 printf("%-6s%-8s%-8s%-8s%-8s%-8s\n", "PID", "AT", "BT", "CT", "TAT", "WT");
 printf("--------------------------------------------------\n");

 int total_wt = 0, total_tat = 0;
 for (int i = 0; i < n; i++) {
 printf("%-6d%-8d%-8d%-8d%-8d%-8d\n", 
 processes[i].pid,
 processes[i].arrival_time,
 processes[i].burst_time,
 processes[i].completion_time,
 processes[i].turnaround_time,
 processes[i].waiting_time);
 total_wt += processes[i].waiting_time;
 total_tat += processes[i].turnaround_time;
 }

 printf("\nAverage Waiting Time: %.2f\n", (float)total_wt / n);
 printf("Average Turnaround Time: %.2f\n", (float)total_tat / n);
}

// FCFS Scheduling
void fcfs_scheduling() {
 // Sort by arrival time
 for (int i = 0; i < n - 1; i++) {
 for (int j = 0; j < n - i - 1; j++) {
 if (processes[j].arrival_time > processes[j + 1].arrival_time) {
 Process temp = processes[j];
 processes[j] = processes[j + 1];
 processes[j + 1] = temp;
 }
 }
 }

 int current_time = 0;

 printf("\nGantt Chart: ");
 for (int i = 0; i < n; i++) {
 if (current_time < processes[i].arrival_time) {
 current_time = processes[i].arrival_time;
 }

 processes[i].start_time = current_time;
 printf("| P%d (%d-%d) ", processes[i].pid, current_time, current_time + processes[i].burst_time);

 processes[i].completion_time = current_time + processes[i].burst_time;
 processes[i].turnaround_time = processes[i].completion_time - processes[i].arrival_time;
 processes[i].waiting_time = processes[i].turnaround_time - processes[i].burst_time;

 current_time = processes[i].completion_time;
 }
 printf("|\n");

 print_results("First-Come, First-Served (FCFS)");
}

// SJF Scheduling (Non-preemptive)
void sjf_scheduling() {
 int current_time = 0;
 int completed = 0;
 int min_burst;
 int min_index;
 int done[MAX_PROCESSES] = {0};

 printf("\nGantt Chart: ");

 while (completed < n) {
 // Find process with minimum burst time among arrived processes
 min_burst = INT_MAX;
 min_index = -1;

 for (int i = 0; i < n; i++) {
 if (!done[i] && processes[i].arrival_time <= current_time) {
 if (processes[i].burst_time < min_burst) {
 min_burst = processes[i].burst_time;
 min_index = i;
 }
 }
 }

 if (min_index == -1) {
 // No process ready, jump to next arrival
 int next_arrival = INT_MAX;
 for (int i = 0; i < n; i++) {
 if (!done[i] && processes[i].arrival_time < next_arrival) {
 next_arrival = processes[i].arrival_time;
 }
 }
 current_time = next_arrival;
 continue;
 }

 // Execute the process
 processes[min_index].start_time = current_time;
 printf("| P%d (%d-%d) ", processes[min_index].pid, 
 current_time, current_time + processes[min_index].burst_time);

 current_time += processes[min_index].burst_time;

 processes[min_index].completion_time = current_time;
 processes[min_index].turnaround_time = processes[min_index].completion_time - processes[min_index].arrival_time;
 processes[min_index].waiting_time = processes[min_index].turnaround_time - processes[min_index].burst_time;

 done[min_index] = 1;
 completed++;
 }
 printf("|\n");

 print_results("Shortest Job First (SJF)");
}

// Round Robin Scheduling
void round_robin_scheduling(int time_quantum) {
 int current_time = 0;
 int completed = 0;
 int queue[MAX_PROCESSES];
 int front = 0, rear = 0;
 int in_queue[MAX_PROCESSES] = {0};

 // Add processes that arrive at time 0
 for (int i = 0; i < n; i++) {
 if (processes[i].arrival_time == 0) {
 queue[rear++] = i;
 in_queue[i] = 1;
 }
 }

 printf("\nGantt Chart: ");

 while (completed < n) {
 if (front >= rear) {
 // Queue empty, jump to next arrival
 int next_arrival = INT_MAX;
 for (int i = 0; i < n; i++) {
 if (!in_queue[i] && processes[i].arrival_time > current_time) {
 next_arrival = processes[i].arrival_time;
 break;
 }
 }
 if (next_arrival == INT_MAX) break;
 current_time = next_arrival;

 // Add newly arrived processes
 for (int i = 0; i < n; i++) {
 if (processes[i].arrival_time <= current_time && !in_queue[i]) {
 queue[rear++] = i;
 in_queue[i] = 1;
 }
 }
 continue;
 }

 int idx = queue[front++];

 if (processes[idx].start_time == -1) {
 processes[idx].start_time = current_time;
 }

 // Execute for time quantum or remaining time
 int exec_time = (processes[idx].remaining_time < time_quantum) ? 
 processes[idx].remaining_time : time_quantum;

 printf("| P%d (%d-%d) ", processes[idx].pid, current_time, current_time + exec_time);

 processes[idx].remaining_time -= exec_time;
 current_time += exec_time;

 // Add newly arrived processes to queue
 for (int i = 0; i < n; i++) {
 if (processes[i].arrival_time <= current_time && !in_queue[i]) {
 queue[rear++] = i;
 in_queue[i] = 1;
 }
 }

 if (processes[idx].remaining_time > 0) {
 queue[rear++] = idx; // Add back to queue
 } else {
 processes[idx].completion_time = current_time;
 processes[idx].turnaround_time = processes[idx].completion_time - processes[idx].arrival_time;
 processes[idx].waiting_time = processes[idx].turnaround_time - processes[idx].burst_time;
 completed++;
 }
 }
 printf("|\n");

 char title[50];
 sprintf(title, "Round Robin (Time Quantum = %d)", time_quantum);
 print_results(title);
}

int main() {
 // Initialize processes: PID, Arrival Time, Burst Time
 init_process(1, 0, 24);
 init_process(2, 1, 3);
 init_process(3, 2, 3);

 // Run FCFS
 printf("\n=== CPU Scheduling Algorithms Demo ===");
 fcfs_scheduling();

 // Reset for next algorithm
 reset_processes();

 // Run SJF
 sjf_scheduling();

 // Reset for next algorithm
 reset_processes();

 // Run Round Robin (quantum = 4)
 round_robin_scheduling(4);

 return 0;
}
